Greedy insertion minimizing weighted sum of travel distance increase and time window tightness violation penalty, with random tie-breaking and mandatory fallback to new assign per order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 || len(dess) != orderCount {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	const alpha = 1.7
	const beta = 0.9
	rndSeed := uint32(total_ship)
	for jj := 0; jj < orderCount; jj++ {
		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj
		bestAssignIdx := -1
		bestScore := 1e100
		tempCosts := make([]float64, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			tempCosts[i] = dispatch.Assigns[i].Cost
		}
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			addOK := dispatch.Assigns[ii].AddShip(shipID, ori, des)
			if !addOK {
				continue
			}
			prevCost := tempCosts[ii]
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			deltaDist := newCost - prevCost
			var twPenalty float64
			curStation := dispatch.Assigns[ii].StationCurrent
			travelTime := cal_dis(curStation, ori)
			arrivalOri := travelTime
			if arrivalOri > float64(ori.TimeEnd) {
				twPenalty += alpha * (arrivalOri - float64(ori.TimeEnd))
			}
			deadhead := cal_dis(ori, des)
			completion := arrivalOri + deadhead
			if completion > float64(des.TimeEnd) {
				twPenalty += beta * (completion - float64(des.TimeEnd))
			}
			score := deltaDist*1.3 + twPenalty*0.6
			dispatch.Assigns[ii].RemoveShip(shipID)
			dispatch.Assigns[ii].GenRoute()
			rndSeed = rndSeed*1664525 + 1013904223
			jitter := float64(rndSeed&0xFFFF) * 1e-8
			if score+jitter < bestScore {
				bestScore = score + jitter
				bestAssignIdx = ii
			}
		}
		inserted := false
		if bestAssignIdx >= 0 {
			finalOK := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if finalOK {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				inserted = true
			}
		}
		if !inserted {
			if dispatch.AssignsLen >= MAXASSIGNS {
				for i := 0; i < dispatch.AssignsLen; i++ {
					dispatch.Assigns[i].Cost = tempCosts[i]
				}
				dispatch.RenewnTotalCost()
				return dispatch
			}
			idx := dispatch.AssignsLen
			ok := dispatch.Assigns[idx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[idx].GenRoute()
				dispatch.AssignsLen++
				inserted = true
			} else {
				for i := 0; i < dispatch.AssignsLen; i++ {
					dispatch.Assigns[i].Cost = tempCosts[i]
				}
				dispatch.RenewnTotalCost()
				return dispatch
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

